insert into public.be_master_data_rows (
  dataset_key, record_key, payload, status, updated_by_email, updated_at, deleted_at
)
select dataset_key, record_key, payload, 'ACTIVE', 'workbook-seed', now(), null
from src
on conflict (dataset_key, record_key) do update set
  payload = excluded.payload,
  status = 'ACTIVE',
  updated_by_email = 'workbook-seed',
  updated_at = now(),
  deleted_at = null;

create or replace function public.be_master_data_upsert_column(
  p_dataset_key text,
  p_field_key text,
  p_label_en text default null,
  p_label_mm text default null,
  p_data_type text default 'text',
  p_required boolean default false,
  p_editable boolean default true,
  p_visible boolean default true,
  p_options jsonb default '[]'::jsonb,
  p_sort_order integer default 999
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
begin
  insert into public.be_master_data_columns (
    dataset_key, field_key, label_en, label_mm, data_type, required, editable, visible, options, sort_order, updated_at
  )
  values (
    p_dataset_key,
    p_field_key,
    coalesce(p_label_en, initcap(replace(p_field_key, '_', ' '))),
    coalesce(p_label_mm, p_label_en, initcap(replace(p_field_key, '_', ' '))),
    coalesce(p_data_type, 'text'),
    coalesce(p_required, false),
    coalesce(p_editable, true),
    coalesce(p_visible, true),
    coalesce(p_options, '[]'::jsonb),
    coalesce(p_sort_order, 999),
    now()
  )
  on conflict (dataset_key, field_key) do update set
    label_en = excluded.label_en,
    label_mm = excluded.label_mm,
    data_type = excluded.data_type,
    required = excluded.required,
    editable = excluded.editable,
    visible = excluded.visible,
    options = excluded.options,
    sort_order = excluded.sort_order,
    updated_at = now();

  return jsonb_build_object('ok', true, 'dataset_key', p_dataset_key, 'field_key', p_field_key);
end;
$$;

create or replace function public.be_master_data_upsert_record(
  p_dataset_key text,
  p_record_key text,
  p_payload jsonb,
  p_actor_email text default null
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
  v_primary_key text;
  v_record_key text;
  v_row public.be_master_data_rows;
begin
  if p_dataset_key is null or length(trim(p_dataset_key)) = 0 then
    raise exception 'dataset_key is required';
  end if;

  select primary_key
    into v_primary_key
  from public.be_master_data_tabs
  where dataset_key = p_dataset_key
    and active = true;

  if v_primary_key is null then
    raise exception 'Unknown master dataset: %', p_dataset_key;
  end if;

  v_record_key := nullif(trim(coalesce(p_record_key, '')), '');

  if v_record_key is null then
    v_record_key := nullif(trim(coalesce(p_payload ->> v_primary_key, '')), '');
  end if;

  if v_record_key is null then
    v_record_key := upper(substr(md5(clock_timestamp()::text || random()::text), 1, 12));
    p_payload := jsonb_set(coalesce(p_payload, '{}'::jsonb), array[v_primary_key], to_jsonb(v_record_key), true);
  end if;

  insert into public.be_master_data_rows (
    dataset_key, record_key, payload, status, updated_by_email, updated_at, deleted_at
  )
  values (
    p_dataset_key,
    v_record_key,
    coalesce(p_payload, '{}'::jsonb),
    coalesce(nullif(p_payload ->> 'status', ''), 'ACTIVE'),
    p_actor_email,
    now(),
    null
  )
  on conflict (dataset_key, record_key) do update set
    payload = excluded.payload,
    status = coalesce(nullif(excluded.payload ->> 'status', ''), public.be_master_data_rows.status, 'ACTIVE'),
    updated_by_email = excluded.updated_by_email,
    updated_at = now(),
    deleted_at = null
  returning * into v_row;

  return jsonb_build_object(
    'ok', true,
    'dataset_key', v_row.dataset_key,
    'record_key', v_row.record_key,
    'row', jsonb_build_object(
      'id', v_row.id,
      'dataset_key', v_row.dataset_key,
      'record_key', v_row.record_key,
      'payload', v_row.payload,
      'status', v_row.status,
      'updated_at', v_row.updated_at
    )
  );
end;
$$;

create or replace function public.be_master_data_delete_record(
  p_dataset_key text,
  p_record_key text,
  p_actor_email text default null
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
  v_count integer;
begin
  update public.be_master_data_rows
  set deleted_at = now(),
      status = 'DELETED',
      updated_by_email = p_actor_email,
      updated_at = now()
  where dataset_key = p_dataset_key
    and record_key = p_record_key
    and deleted_at is null;

  get diagnostics v_count = row_count;

  return jsonb_build_object(
    'ok', v_count > 0,
    'dataset_key', p_dataset_key,
    'record_key', p_record_key,
    'deleted', v_count
  );
end;
$$;

create or replace function public.be_master_data_bulk_upsert_records(
  p_dataset_key text,
  p_rows jsonb,
  p_actor_email text default null
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
  v_row jsonb;
  v_count integer := 0;
  v_pk text;
  v_key text;
begin
  select primary_key into v_pk
  from public.be_master_data_tabs
  where dataset_key = p_dataset_key;

  if v_pk is null then
    raise exception 'Unknown master dataset: %', p_dataset_key;
  end if;

  for v_row in select * from jsonb_array_elements(coalesce(p_rows, '[]'::jsonb))
  loop
    v_key := nullif(v_row ->> v_pk, '');
    perform public.be_master_data_upsert_record(p_dataset_key, v_key, v_row, p_actor_email);
    v_count := v_count + 1;
  end loop;

  return jsonb_build_object('ok', true, 'dataset_key', p_dataset_key, 'upserted', v_count);
end;
$$;

create or replace function public.be_master_data_page_snapshot()
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
  v_tabs jsonb;
  v_records jsonb;
  v_merchants jsonb;
  v_riders jsonb;
  v_drivers jsonb;
  v_helpers jsonb;
  v_employees jsonb;
  v_fleets jsonb;
  v_workforce jsonb;
  v_result jsonb;
begin
  select coalesce(jsonb_agg(
    jsonb_build_object(
      'dataset_key', t.dataset_key,
      'sheet_name', t.sheet_name,
      'display_name_en', t.display_name_en,
      'display_name_mm', t.display_name_mm,
      'category', t.category,
      'primary_key', t.primary_key,
      'sort_order', t.sort_order,
      'active', t.active,
      'row_count', (
        select count(*)
        from public.be_master_data_rows r
        where r.dataset_key = t.dataset_key
          and r.deleted_at is null
      ),
      'fields', coalesce((
        select jsonb_agg(
          jsonb_build_object(
            'field_key', c.field_key,
            'label_en', c.label_en,
            'label_mm', c.label_mm,
            'data_type', c.data_type,
            'required', c.required,
            'editable', c.editable,
            'visible', c.visible,
            'options', coalesce(c.options, '[]'::jsonb),
            'sort_order', c.sort_order
          )
          order by c.sort_order, c.field_key
        )
        from public.be_master_data_columns c
        where c.dataset_key = t.dataset_key
          and c.visible = true
      ), '[]'::jsonb)
    )
    order by t.sort_order, t.dataset_key
  ), '[]'::jsonb)
  into v_tabs
  from public.be_master_data_tabs t
  where t.active = true;

  select coalesce(jsonb_object_agg(dataset_key, rows), '{}'::jsonb)
  into v_records
  from (
    select r.dataset_key,
           coalesce(jsonb_agg(
             jsonb_build_object(
               'id', r.id,
               'dataset_key', r.dataset_key,
               'record_key', r.record_key,
               'payload', r.payload,
               'status', r.status,
               'updated_at', r.updated_at,
               'updated_by_email', r.updated_by_email
             )
             order by r.record_key
           ), '[]'::jsonb) as rows
    from public.be_master_data_rows r
    where r.deleted_at is null
    group by r.dataset_key
  ) s;

  select coalesce(jsonb_agg(payload || jsonb_build_object(
    'code', payload ->> 'merchant_code',
    'name', payload ->> 'merchant_name',
    'phone', payload ->> 'phone_primary',
    'town', payload ->> 'township',
    'address', coalesce(payload ->> 'default_pickup_address', payload ->> 'address_line_1'),
    'status', coalesce(payload ->> 'contract_status', case when coalesce(payload ->> 'is_active','true') in ('true','Yes','yes','1') then 'Active' else 'Inactive' end)
  ) order by record_key), '[]'::jsonb)
  into v_merchants
  from public.be_master_data_rows
  where dataset_key = 'merchant_master' and deleted_at is null;

  select coalesce(jsonb_agg(payload || jsonb_build_object(
    'id', payload ->> 'rider_id',
    'name', payload ->> 'rider_name',
    'workforce_code', payload ->> 'rider_id',
    'workforce_name', payload ->> 'rider_name',
    'phone', payload ->> 'phone_primary',
    'role', 'RIDER',
    'status', payload ->> 'status'
  ) order by record_key), '[]'::jsonb)
  into v_riders
  from public.be_master_data_rows
  where dataset_key = 'rider_master' and deleted_at is null;

  select coalesce(jsonb_agg(payload || jsonb_build_object(
    'id', payload ->> 'driver_id',
    'name', payload ->> 'driver_name',
    'workforce_code', payload ->> 'driver_id',
    'workforce_name', payload ->> 'driver_name',
    'phone', payload ->> 'phone_primary',
    'role', 'DRIVER',
    'status', payload ->> 'status'
  ) order by record_key), '[]'::jsonb)
  into v_drivers
  from public.be_master_data_rows
  where dataset_key = 'driver_master' and deleted_at is null;

  select coalesce(jsonb_agg(payload || jsonb_build_object(
    'id', payload ->> 'helper_id',
    'name', payload ->> 'helper_name',
    'workforce_code', payload ->> 'helper_id',
    'workforce_name', payload ->> 'helper_name',
    'phone', payload ->> 'phone_primary',
    'role', 'HELPER',
    'status', payload ->> 'status'
  ) order by record_key), '[]'::jsonb)
  into v_helpers
  from public.be_master_data_rows
  where dataset_key = 'helper_master' and deleted_at is null;

  select coalesce(jsonb_agg(payload || jsonb_build_object(
    'id', payload ->> 'employee_id',
    'name', payload ->> 'employee_name',
    'workforce_code', payload ->> 'employee_id',
    'workforce_name', payload ->> 'employee_name',
    'phone', payload ->> 'phone_primary',
    'role', coalesce(payload ->> 'role_id','EMPLOYEE'),
    'status', payload ->> 'status'
  ) order by record_key), '[]'::jsonb)
  into v_employees
  from public.be_master_data_rows
  where dataset_key = 'employee_master' and deleted_at is null;

  select coalesce(jsonb_agg(payload || jsonb_build_object(
    'id', payload ->> 'fleet_id',
    'vehicle_no', payload ->> 'vehicle_no',
    'type', payload ->> 'vehicle_type',
    'capacity', payload ->> 'capacity_kg',
    'status', payload ->> 'status'
  ) order by record_key), '[]'::jsonb)
  into v_fleets
  from public.be_master_data_rows
  where dataset_key = 'fleet_master' and deleted_at is null;

  v_workforce := coalesce(v_riders, '[]'::jsonb)
    || coalesce(v_drivers, '[]'::jsonb)
    || coalesce(v_helpers, '[]'::jsonb)
    || coalesce(v_employees, '[]'::jsonb);

  v_result := jsonb_build_object(
    'ok', true,
    'datasets', v_tabs,
    'tabs', v_tabs,
    'records_by_dataset', v_records,
    'counts', jsonb_build_object(
      'datasets', jsonb_array_length(v_tabs),
      'rows', (select count(*) from public.be_master_data_rows where deleted_at is null),
      'columns', (select count(*) from public.be_master_data_columns)
    ),

    -- Backward-compatible keys for existing pages that fall back to this snapshot.
    'merchants', v_merchants,
    'merchant_master', coalesce(v_records -> 'merchant_master', '[]'::jsonb),
    'Merchant_Master', coalesce(v_records -> 'merchant_master', '[]'::jsonb),

    'riders', v_riders,
    'Rider_Master', v_riders,
    'drivers', v_drivers,
    'Driver_Master', v_drivers,
    'helpers', v_helpers,
    'Helper_Master', v_helpers,
    'employees', v_employees,
    'Employee_Master', v_employees,
    'workforce', v_workforce,
    'workforce_accounts', v_workforce,

    'fleets', v_fleets,
    'Fleet_Master', v_fleets,

    'service_types', coalesce(v_records -> 'service_types', '[]'::jsonb),
    'weight_brackets', coalesce(v_records -> 'weight_brackets', '[]'::jsonb),
    'vehicle_capacity', coalesce(v_records -> 'vehicle_capacity', '[]'::jsonb),
    'zones', coalesce(v_records -> 'zone_master', '[]'::jsonb),
    'townships', coalesce(v_records -> 'township_master', '[]'::jsonb),
    'cod_fee_rules', coalesce(v_records -> 'cod_fee_rules', '[]'::jsonb),
    'surcharge_rules', coalesce(v_records -> 'surcharge_rules', '[]'::jsonb),
    'cargo_dropoff_rates', coalesce(v_records -> 'cargo_dropoff_rate', '[]'::jsonb)
  );

  return v_result;
end;
$$;

create or replace view public.be_v_master_data_live_rows as
select
  r.id,
  r.dataset_key,
  t.display_name_en,
  t.category,
  t.primary_key,
  r.record_key,
  r.payload,
  r.status,
  r.updated_at,
  r.updated_by_email
from public.be_master_data_rows r
join public.be_master_data_tabs t on t.dataset_key = r.dataset_key
where r.deleted_at is null
  and t.active = true;

create or replace function public.be_master_data_healthcheck()
returns jsonb
language sql
stable
as $$
  select jsonb_build_object(
    'ok', true,
    'datasets', (select count(*) from public.be_master_data_tabs where active),
    'columns', (select count(*) from public.be_master_data_columns),
    'rows', (select count(*) from public.be_master_data_rows where deleted_at is null),
    'sample_tabs', (select jsonb_agg(dataset_key order by sort_order) from public.be_master_data_tabs where active)
  );
$$;

notify pgrst, 'reload schema';
